const REPORT_CHAT_ID = 'TELEGRAM_CHAT_ID_HERE';

const input = $json;
const now = new Date().toISOString();

const isTelegram = Boolean(input.message && input.message.chat);

const commandMap = {
  '/report': 'full',
  '/health': 'health',
  '/speed': 'speed',
  '/help': 'help'
};

if (isTelegram) {
  const text = (input.message.text || '').trim();
  const chatId = String(input.message.chat.id);
  const messageId = input.message.message_id;

  const commandRaw = text.split(/\s+/)[0] || '';
  const command = commandRaw.replace(/@\w+$/, '').toLowerCase();

  const runMode = commandMap[command] || null;

  return [
    {
      json: {
        source: 'telegram',
        should_run: Boolean(runMode),
        chat_id: chatId,
        message_id: messageId,
        command,
        run_mode: runMode || 'unknown',
        requested_at: now,
        is_manual: true
      }
    }
  ];
}

return [
  {
    json: {
      source: 'schedule',
      should_run: true,
      chat_id: REPORT_CHAT_ID,
      message_id: null,
      command: 'schedule',
      run_mode: 'full',
      requested_at: now,
      is_manual: false
    }
  }
];

const runMode = $json.run_mode;

const runHealth = runMode === 'full' || runMode === 'health';
const runSpeed = runMode === 'full' || runMode === 'speed';

const CONFIG = {
  project_slug: '',
  project_name: '',
  base_url: '',

  product_path: '',
  cart_path: '',

  health_runner_url: '',
  speed_json_url: '',
  speed_image_url: '',

  health_timeout_ms: 45000,
  speed_timeout_ms: 60000,

  selectors: {
    product_gallery: ''
  },

  product: {
    expected_title_contains: '',
    expected_quantity_after_update: 1,
    accessory_variants: []
  },

  expectations: {
    base_accessory_id: '',
    expected_paid_accessory_example: '',
    expected_add_delta: 1,
    expected_accessory_add_delta: 1,
    expected_update_delta: 0,
    expected_double_click_delta: 1,
    expected_quantity_after_update: 1,
    motivator_max_discount_total: 30000
  }
};

function joinUrl(base, path) {
  if (!base) return '';
  if (!path) return base.replace(/\/+$/, '');

  return `${base.replace(/\/+$/, '')}/${path.replace(/^\/+/, '')}`;
}

const now = new Date();
const reportId = `${CONFIG.project_slug || 'project'}_${now.toISOString().replace(/[:.]/g, '-')}`;

const homeUrl = CONFIG.base_url ? `${CONFIG.base_url.replace(/\/+$/, '')}/` : '';
const productUrl = joinUrl(CONFIG.base_url, CONFIG.product_path);
const cartUrl = joinUrl(CONFIG.base_url, CONFIG.cart_path);

return [
  {
    json: {
      report_id: reportId,

      source: $json.source,
      command: $json.command,
      run_mode: runMode,
      is_manual: $json.is_manual,
      requested_at: $json.requested_at,

      telegram: {
        chat_id: $json.chat_id,
        message_id: $json.message_id
      },

      checks: {
        health: runHealth,
        speed: runSpeed
      },

      project: {
        slug: CONFIG.project_slug,
        name: CONFIG.project_name,
        base_url: CONFIG.base_url
      },

      runners: {
        health_url: CONFIG.health_runner_url,
        speed_json_url: CONFIG.speed_json_url,
        speed_image_url: CONFIG.speed_image_url
      },

      pages: {
        home: {
          id: 'home',
          title: 'Home',
          url: homeUrl
        },
        product: {
          id: 'product',
          title: 'Product page',
          url: productUrl
        },
        cart: {
          id: 'cart',
          title: 'Cart',
          url: cartUrl,
          requires_added_product: true
        }
      },

      health: {
        timeout_ms: CONFIG.health_timeout_ms,

        selectors: CONFIG.selectors,

        flow: {
          clear_cart_before_test: true,
          product_url: productUrl,
          cart_url: cartUrl,

          checks: [
            {
              id: 'product_gallery_visible',
              title: 'Product gallery visible',
              page: 'product'
            },
            {
              id: 'product_common_sanity',
              title: 'Product common.v2, smartCart patch, EventBus',
              page: 'product'
            },
            {
              id: 'add_product_to_cart',
              title: 'Add product to cart',
              page: 'product'
            },
            {
              id: 'add_product_with_accessory',
              title: 'Add product with accessory',
              page: 'product'
            },
            {
              id: 'update_accessory_without_quantity_change',
              title: 'Update accessory without quantity change',
              page: 'product'
            },
            {
              id: 'double_click_add_guard',
              title: 'Double click add guard',
              page: 'product'
            },
            {
              id: 'cart_sanity',
              title: 'Cart init, common.v2, EventBus',
              page: 'cart'
            },
            {
              id: 'cart_no_duplicate_lines',
              title: 'Cart no duplicate lines',
              page: 'cart'
            },
            {
              id: 'cart_qty_and_total',
              title: 'Cart quantity and total',
              page: 'cart'
            },
            {
              id: 'cart_motivator_popup',
              title: 'Cart motivator popup',
              page: 'cart'
            },
            {
              id: 'cart_remove_line',
              title: 'Cart remove line',
              page: 'cart'
            }
          ]
        },

        product: CONFIG.product,

        expectations: CONFIG.expectations
      },

      speed: {
        device: 'desktop',
        timeout_ms: CONFIG.speed_timeout_ms,
        profile: 'datacenter'
      }
    }
  }
];

return [
  {
    json: {
      ...$json,
      health_result: {
        status: 'skipped',
        skipped: true,
        summary: {
          total: 0,
          passed: 0,
          warnings: 0,
          failed: 0
        },
        checks: [],
        errors: [],
        warnings: [],
        artifacts: {}
      }
    }
  }
];

return [
  {
    json: {
      ...$json,
      speed_result: {
        ok: false,
        skipped: true,
        status: 'skipped',
        status_title: '⏭️ skipped',
        telegramMessage: '',
        booster: {},
        competitors: {},
        errors: []
      }
    }
  }
];

const data = $json;

function statusIcon(status) {
  if (status === 'ok') return '✅';
  if (status === 'warn' || status === 'warning') return '⚠️';
  if (status === 'bad' || status === 'failed' || status === 'error') return '❌';
  if (status === 'skipped') return '⏭️';
  return '•';
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function cleanError(check) {
  const raw = check.error || check.actual?.error || '';

  if (!raw) return 'error without message';

  return escapeHtml(
    String(raw)
      .replace(/\n/g, ' ')
      .replace(/\s+/g, ' ')
      .replace('Call log:', '')
      .trim()
      .slice(0, 350)
  );
}

function line(check, okText, failText) {
  if (!check) {
    return `❌ ${failText}: check did not return`;
  }

  if (check.status === 'ok') {
    return `✅ ${okText}`;
  }

  if (check.status === 'warning' || check.status === 'warn') {
    return `⚠️ ${failText}: ${cleanError(check)}`;
  }

  return `❌ ${failText}: ${cleanError(check)}`;
}

function findCheck(id) {
  return (data.health_result?.checks || []).find(check => check.id === id);
}

const health = data.health_result || {
  status: 'skipped',
  skipped: true,
  summary: {
    total: 0,
    passed: 0,
    warnings: 0,
    failed: 0
  },
  checks: [],
  errors: [],
  warnings: []
};

const speed = data.speed_result || {
  status: 'skipped',
  skipped: true,
  telegramMessage: '',
  errors: []
};

const timezone = data.timezone || data.report_timezone || 'UTC';

const date = new Date().toLocaleString('en-GB', {
  timeZone: timezone,
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

const lines = [];

lines.push('📊 <b>Daily report</b>');

if (data.project?.name) {
  lines.push(`Project: ${escapeHtml(data.project.name)}`);
}

lines.push(`Date: ${date}`);
lines.push(`Mode: ${escapeHtml(data.run_mode)}`);
lines.push('');

if (health.skipped) {
  lines.push('⏭️ Health check skipped');
} else {
  const summary = health.summary || {};

  lines.push(`Health check: ${statusIcon(health.status)} ${summary.passed || 0}/${summary.total || 0} passed`);
  lines.push('');

  lines.push('<b>Product page:</b>');
  lines.push(line(
    findCheck('product_common_sanity'),
    'Common.v2, smartCart patch and EventBus loaded',
    'Common.v2, smartCart patch and EventBus'
  ));
  lines.push(line(
    findCheck('product_gallery_visible'),
    'Product gallery is visible',
    'Product gallery'
  ));
  lines.push(line(
    findCheck('add_product_to_cart'),
    'Add to cart works',
    'Add to cart'
  ));
  lines.push(line(
    findCheck('add_product_with_accessory'),
    'Adding product with accessory works',
    'Adding product with accessory'
  ));
  lines.push(line(
    findCheck('update_accessory_without_quantity_change'),
    'Accessory update does not duplicate quantity',
    'Accessory update'
  ));
  lines.push(line(
    findCheck('double_click_add_guard'),
    'Double-click guard works',
    'Double-click guard'
  ));

  lines.push('');
  lines.push('<b>Cart:</b>');
  lines.push(line(
    findCheck('cart_sanity'),
    'Cart init, common.v2 and EventBus loaded',
    'Cart init, common.v2 and EventBus'
  ));
  lines.push(line(
    findCheck('cart_no_duplicate_lines'),
    'No duplicate cart lines',
    'Duplicate cart lines check'
  ));
  lines.push(line(
    findCheck('cart_qty_and_total'),
    'Quantity and total are valid',
    'Quantity and total'
  ));
  lines.push(line(
    findCheck('cart_motivator_popup'),
    'Motivator popup opens and shows content',
    'Motivator popup'
  ));
  lines.push(line(
    findCheck('cart_remove_line'),
    'Removing cart line works',
    'Remove cart line'
  ));

  if (health.errors && health.errors.length) {
    lines.push('');
    lines.push('<b>Health errors:</b>');

    for (const err of health.errors) {
      if (typeof err === 'string') {
        lines.push(`❌ ${escapeHtml(err)}`);
      } else {
        lines.push(`❌ ${escapeHtml(err.title || err.id || 'Error')}: ${cleanError(err)}`);
      }
    }
  }
}

if (speed.skipped) {
  lines.push('');
  lines.push('⏭️ Speed check skipped');
} else {
  lines.push('');

  if (speed.telegramMessage) {
    lines.push(speed.telegramMessage);
  } else {
    lines.push(`⚡ <b>Speed:</b> ${statusIcon(speed.status)} no detailed data`);
  }

  if (speed.errors && speed.errors.length) {
    lines.push('');
    lines.push('<b>Speed errors:</b>');

    for (const err of speed.errors) {
      lines.push(`❌ ${escapeHtml(typeof err === 'string' ? err : JSON.stringify(err))}`);
    }
  }
}

let finalStatus = 'ok';

if (
  (health.summary && health.summary.failed > 0) ||
  ['bad', 'failed', 'error'].includes(speed.status)
) {
  finalStatus = 'failed';
} else if (
  (health.summary && health.summary.warnings > 0) ||
  ['warn', 'warning'].includes(speed.status)
) {
  finalStatus = 'warning';
}

lines.push('');
lines.push(`<b>Result:</b> ${statusIcon(finalStatus)} ${
  finalStatus === 'ok'
    ? 'no critical issues'
    : finalStatus === 'warning'
      ? 'warnings found'
      : 'errors found'
}`);

return [
  {
    json: {
      ...data,
      final_status: finalStatus,
      telegram_message: lines.join('\n')
    }
  }
];

const data = $json;

const payload = {
  report_id: data.report_id,

  project: data.project,

  pages: {
    home: data.pages.home
  },

  speed: {
    device: data.speed?.device || 'desktop',
    timeout_ms: data.speed?.timeout_ms || 60000,
    profile: data.speed?.profile || 'datacenter'
  },

  timeout_ms: data.speed?.timeout_ms || 60000
};

return [
  {
    json: {
      ...data,
      speed_runner_payload: payload
    }
  }
];

const original = $('Build Speed Runner Payload').first().json;

let response = $json;

if (response && response.body !== undefined) {
  response = response.body;
}

if (response && response.data !== undefined) {
  response = response.data;
}

if (typeof response === 'string') {
  try {
    response = JSON.parse(response);
  } catch (error) {
    response = {
      ok: false,
      status: 'error',
      status_title: '❌ error',
      telegramMessage: '❌ <b>Speed: error</b>\n\nRunner returned invalid JSON.',
      booster: {},
      competitors: {},
      errors: ['Runner returned invalid JSON']
    };
  }
}

if (!response || typeof response !== 'object' || Array.isArray(response)) {
  response = {
    ok: false,
    status: 'error',
    status_title: '❌ error',
    telegramMessage: '❌ <b>Speed: error</b>\n\nRunner returned empty or invalid response.',
    booster: {},
    competitors: {},
    errors: ['Runner returned empty or invalid response']
  };
}

const speedResult = {
  ok: response.ok === true,
  skipped: response.skipped === true,
  status: response.status || 'error',
  status_title: response.status_title || '⚠️ unknown status',
  telegramMessage: response.telegramMessage || '',
  booster:
    response.booster && typeof response.booster === 'object'
      ? response.booster
      : {},
  competitors:
    response.competitors && typeof response.competitors === 'object'
      ? response.competitors
      : {},
  errors: Array.isArray(response.errors) ? response.errors : []
};

return [
  {
    json: {
      ...original,
      speed_runner_response: response,
      speed_result: speedResult
    }
  }
];

const data = $json;

const health = data.health || {};
const expectations = health.expectations || {};
const selectors = health.selectors || {};

const payload = {
  report_id: data.report_id,

  project: data.project,

  pages: {
    home: data.pages.home,
    product: data.pages.product,
    cart: data.pages.cart
  },

  options: {
    timeout_ms: health.timeout_ms || 45000,
    make_screenshot_on_error: false,
    collect_console_errors: false,
    collect_failed_requests: false,
    isolate_mutating_tests: true
  },

  expectations: {
    base_accessory_id: expectations.base_accessory_id || '',
    expected_paid_accessory_example: expectations.expected_paid_accessory_example || '',
    expected_add_delta: expectations.expected_add_delta ?? 1,
    expected_accessory_add_delta: expectations.expected_accessory_add_delta ?? 1,
    expected_update_delta: expectations.expected_update_delta ?? 0,
    expected_double_click_delta: expectations.expected_double_click_delta ?? 1,
    expected_quantity_after_update: expectations.expected_quantity_after_update ?? 1,
    motivator_max_discount_total: expectations.motivator_max_discount_total ?? 30000
  },

  health_tests: {
    product_page: [
      {
        id: 'product_gallery_visible',
        title: 'Product gallery visible',
        type: 'visibility',
        selector: selectors.product_gallery || '',
        expected: true
      },
      {
        id: 'product_common_sanity',
        title: 'Product common.v2, smartCart patch, EventBus',
        type: 'console_evaluate',
        expected: {
          common_once: true,
          smart_cart_add_patched: true,
          event_bus_type: 'object'
        }
      },
      {
        id: 'add_product_to_cart',
        title: 'Add product to cart',
        type: 'cart_action',
        expected: {
          delta: expectations.expected_add_delta ?? 1
        }
      },
      {
        id: 'add_product_with_accessory',
        title: 'Add product with accessory',
        type: 'cart_action_with_accessory',
        expected: {
          delta: expectations.expected_accessory_add_delta ?? 1,
          lines_count: 1,
          accessory_not_base: true
        }
      },
      {
        id: 'update_accessory_without_quantity_change',
        title: 'Update accessory without quantity change',
        type: 'cart_update_accessory',
        expected: {
          delta: expectations.expected_update_delta ?? 0,
          quantity: expectations.expected_quantity_after_update ?? 1,
          lines_count: 1,
          accessory_not_base: true
        }
      },
      {
        id: 'double_click_add_guard',
        title: 'Double click add guard',
        type: 'double_click_guard',
        expected: {
          delta: expectations.expected_double_click_delta ?? 1,
          no_duplicate_lines: true
        }
      }
    ],

    cart_page: [
      {
        id: 'cart_sanity',
        title: 'Cart init, common.v2, EventBus',
        type: 'cart_sanity',
        requires_product_in_cart: true,
        expected: {
          cart_motivator_initialized: true,
          common_once: true,
          event_bus_type: 'object'
        }
      },
      {
        id: 'cart_no_duplicate_lines',
        title: 'Cart no duplicate lines',
        type: 'cart_no_duplicates',
        requires_product_in_cart: true,
        expected: {
          ok: true
        }
      },
      {
        id: 'cart_qty_and_total',
        title: 'Cart quantity and total',
        type: 'cart_qty_total',
        requires_product_in_cart: true,
        expected: {
          qty_gt_zero: true,
          total_price_gt_zero: true
        }
      },
      {
        id: 'cart_motivator_popup',
        title: 'Cart motivator popup',
        type: 'cart_motivator_popup',
        requires_product_in_cart: true,
        expected: {
          cards_gt_zero_or_total_gte_max: true
        }
      },
      {
        id: 'cart_remove_line',
        title: 'Cart remove line',
        type: 'cart_remove_line',
        requires_product_in_cart: true,
        destructive: true,
        expected: {
          lines_decreased: true
        }
      }
    ]
  }
};

return [
  {
    json: {
      ...data,
      health_runner_payload: payload
    }
  }
];

const original = $('Build Health Runner Payload').first().json;

let response = $json;

if (response && response.body !== undefined) {
  response = response.body;
}

if (response && response.data !== undefined) {
  response = response.data;
}

if (typeof response === 'string') {
  try {
    response = JSON.parse(response);
  } catch (error) {
    response = {
      status: 'error',
      skipped: false,
      summary: {
        total: 0,
        passed: 0,
        warnings: 0,
        failed: 1
      },
      checks: [],
      errors: ['Health runner returned invalid JSON'],
      warnings: []
    };
  }
}

if (!response || typeof response !== 'object' || Array.isArray(response)) {
  response = {
    status: 'error',
    skipped: false,
    summary: {
      total: 0,
      passed: 0,
      warnings: 0,
      failed: 1
    },
    checks: [],
    errors: ['Health runner returned empty or invalid response'],
    warnings: []
  };
}

const healthResult = {
  status: response.status || 'error',
  skipped: response.skipped === true,
  summary: response.summary || {
    total: 0,
    passed: 0,
    warnings: 0,
    failed: 1
  },
  checks: Array.isArray(response.checks) ? response.checks : [],
  errors: Array.isArray(response.errors) ? response.errors : [],
  warnings: Array.isArray(response.warnings) ? response.warnings : [],
  artifacts: response.artifacts || {}
};

return [
  {
    json: {
      ...original,
      health_runner_response: response,
      health_result: healthResult
    }
  }
];
